// src/api.ts
async function request(endpoint, options = {}) {
  const url = new URL(endpoint, API_BASE_URL);
  if (options.token) {
    url.searchParams.set("user_token", options.token);
  }
  try {
    const response = await fetch(url.toString(), {
      method: options.method || "GET",
      headers: options.body ? { "Content-Type": "application/json" } : void 0,
      body: options.body ? JSON.stringify(options.body) : void 0
    });
    if (!response.ok) {
      const text = await response.text();
      return { error: text || response.statusText, status: response.status };
    }
    const data = await response.json();
    return { data, status: response.status };
  } catch (error) {
    return { error: error.message, status: 0 };
  }
}
async function login(username, password2) {
  return request("/users/sign_in.json", {
    method: "POST",
    body: {
      user: { login: username, password: password2 }
    }
  });
}
async function signup(username, email, password2) {
  return request("/users.json", {
    method: "POST",
    body: {
      user: { username, email, password: password2 }
    }
  });
}
async function fetchUser(username, token) {
  return request(`/${username}.json`, { token });
}
async function searchRepository(username, slug, token) {
  const url = `/${username}/repositories.json`;
  const fullUrl = new URL(url, API_BASE_URL);
  fullUrl.searchParams.set("user_token", token);
  fullUrl.searchParams.set("slug", slug);
  return request(fullUrl.pathname + fullUrl.search);
}
async function createRepository(username, token, name, policy, hasAutofix) {
  return request(`/${username}/repositories.json`, {
    method: "POST",
    token,
    body: {
      repository: { name, policy, has_autofix: hasAutofix }
    }
  });
}
async function fetchPolicy(repositoryUUID, token) {
  return request(`/${repositoryUUID}/policy.json`, { token });
}
async function createCommitAttempt(repositoryUUID, token, sha, branch, message) {
  return request(`/${repositoryUUID}/commit_attempts.json`, {
    method: "POST",
    token,
    body: {
      commit_attempt: { sha, branch, message }
    }
  });
}
async function postReport(token, report) {
  return request("/policy_checks.json", {
    method: "POST",
    token,
    body: { policy_check: report }
  });
}

// src/auth.ts
import fs3 from "fs";
import chalk2 from "chalk";
function getUsername() {
  try {
    return fs3.readFileSync(USERNAME_PATH, "utf-8").trim();
  } catch {
    return null;
  }
}
function getToken() {
  try {
    return fs3.readFileSync(TOKEN_PATH, "utf-8").trim();
  } catch {
    return null;
  }
}
function isLoggedIn() {
  return !!(getUsername() && getToken());
}
function saveCredentials(username, token) {
  ensureDir(REFS_DIR);
  fs3.writeFileSync(USERNAME_PATH, username, "utf-8");
  fs3.writeFileSync(TOKEN_PATH, token, "utf-8");
}
function clearCredentials() {
  try {
    if (fs3.existsSync(USERNAME_PATH)) fs3.unlinkSync(USERNAME_PATH);
    if (fs3.existsSync(TOKEN_PATH)) fs3.unlinkSync(TOKEN_PATH);
  } catch {
  }
}
async function login2(username, password2) {
  const result = await login(username, password2);
  if (result.data) {
    saveCredentials(result.data.username, result.data.authentication_token);
    console.log(`Logged in as ${chalk2.green(result.data.username)}.`);
    return true;
  }
  console.log(chalk2.red("Login failed."), result.error || "Invalid credentials.");
  return false;
}
async function signup2(username, email, password2) {
  const result = await signup(username, email, password2);
  if (result.data) {
    saveCredentials(result.data.username, result.data.authentication_token);
    console.log(`Account created. Logged in as ${chalk2.green(result.data.username)}.`);
    return true;
  }
  console.log(chalk2.red("Signup failed."), result.error || "Unable to create account.");
  return false;
}
function logout() {
  clearCredentials();
  console.log("Logged out.");
}
async function printStatus() {
  const username = getUsername();
  const token = getToken();
  if (!username || !token) {
    console.log(`Not logged in. Run ${chalk2.cyan("lint auth login")} to sign in.`);
    return;
  }
  const result = await fetchUser(username, token);
  if (result.data) {
    console.log(`Logged in as ${chalk2.green(username)}.`);
  } else {
    console.log(`Stored as ${chalk2.yellow(username)} (unable to verify \u2014 API may be offline).`);
  }
}

